INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("うん、これでいいと思う。\n傷はきれいに塞がったけど、\nまだどこか痛んだりするかな？", 0, 20022, 10, 0, 11, 1200220005, 1, 0, 1, 100211);
