INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("そうかい。\nじゃあまずは、焚火の枝を集める運命を\n受け入れてもらえるかい？", 0, 20052, 10, 0, 11, 1200520010, 1, 0, 1, 105611);
