INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("ねねね！\nみんなで記念撮影しよ？\nあとで見返したら絶対エモいっしょ！", 0, 20162, 10, 0, 11, 1201620005, 1, 0, 1, 101611);
