INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("vo_travel_talk_20018_01", "", 20182, 0, "", 21, 1201820007, 0, "", "", "vo_travel_talk");
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("陛下直々のご命令とあれば、\nこのクレジッタ・キャッシュ！\nご満足いただける大秘宝を、\nなんとしても手に入れてみせますわ！", 0, 20182, 10, 0, 11, 1201820008, 1, 0, 1, 118011);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("", "", 20182, "", "", 91, 1201820009, "", "", "", 0);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("travel_topdrama_r_2000_talk_thinking", "", 20182, 1, 0.2, 3, 1201820010, "", "", "", 118011);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("vo_travel_talk_20018_02", "", 20182, 0, "", 21, 1201820011, 0, "", "", "vo_travel_talk");
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("……それに、手ぶらで帰ったとなると\n秘書にまた小言を言われそうですし。\nあの子がグゥの音も出なくなるくらい\n稼いで稼いで稼ぎますわよ～っ！", 0, 20182, 10, 0, 11, 1201820012, 1, 0, 1, 118011);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("", "", 20182, "", "", 91, 1201820013, "", "", "", 0);
